head.script:
scwin.vCoCd = "";
scwin.vCoClsCd = "";
scwin.vUserHomeClsCd = "";

scwin.KOREA_WON = "KRW";
scwin.ADJM_MTHDCD_PREPAY = "";
scwin.ADJM_MTHDCD_SUSPAY = "";
scwin.ADJM_MTHDCD_NOPAY = "";
scwin.ADJM_MTHDCD_LONG_NOPAY = "";
scwin.ADJM_MTHDCD_LONG_NOPAY_LEASE = "";
scwin.NO_DEDUCT_CLS_CD = "";
scwin.CO_CLS_CD_DONGBU = "";
scwin.SUBSIDIARY_USER_HOME_CLS_CD = "";
scwin.EVID_CLSCD_COR_CARD = "";
scwin.EVID_CLSCD_PRSN_CARD = "";
scwin.DG_TRUE = 1;

scwin.IsRowPosChange = false;
scwin.g_sCurrDate = "";
scwin.rowCopyYn = 0;
scwin.checkExchRt = 0;
scwin.checkMain = false;

scwin.hid_supplierCrn = "";
scwin.hid_cardNo = "";
scwin.hid_vatDeclarAcctDeptCd = "";
scwin.hid_adjmAcctDeptCd = "";
scwin.hid_clntNo = "";
scwin.hid_clntNo1 = "";
scwin.hid_asetKndCd = "";
scwin.hid_asetKndNm = "";
scwin.hid_acqAcctDeptCd = "";
scwin.hid_lsClntNo = "";
scwin.hid_taxOfficeCd = "";
scwin.hid_deprMthdCd = "";
scwin.hid_svcLife = "";
scwin.hid_svcLifeMonth = "";
scwin.hid_taxLawDeprMthdCd = "";
scwin.hid_asetPatternNm = "";
scwin.hid_asetAcqAcctCd = "";
scwin.hid_zip = "";
scwin.txtCoCd = "";
scwin.txtCoClsCd = "";
scwin.txt_stdExch = "";
scwin.txt_clntNm1 = "";

scwin.onpageload = function() {
    scwin.vCoCd = $c.ses.getCoCd() || "";
    scwin.vCoClsCd = $c.ses.getCoClsCd() || "";
    scwin.vUserHomeClsCd = $c.ses.getUserHomeClsCd() || "";
    scwin.g_sCurrDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    scwin.ADJM_MTHDCD_PREPAY = $c.data.getConstant("ADJM_MTHDCD_PREPAY") || "";
    scwin.ADJM_MTHDCD_SUSPAY = $c.data.getConstant("ADJM_MTHDCD_SUSPAY") || "";
    scwin.ADJM_MTHDCD_NOPAY = $c.data.getConstant("ADJM_MTHDCD_NOPAY") || "";
    scwin.ADJM_MTHDCD_LONG_NOPAY = $c.data.getConstant("ADJM_MTHDCD_LONG_NOPAY") || "";
    scwin.ADJM_MTHDCD_LONG_NOPAY_LEASE = $c.data.getConstant("ADJM_MTHDCD_LONG_NOPAY_LEASE") || "";
    scwin.NO_DEDUCT_CLS_CD = $c.data.getConstant("NO_DEDUCT_CLS_CD") || "";
    scwin.CO_CLS_CD_DONGBU = $c.data.getConstant("CO_CLS_CD_DONGBU") || "";
    scwin.SUBSIDIARY_USER_HOME_CLS_CD = $c.data.getConstant("SUBSIDIARY_USER_HOME_CLS_CD") || "";
    scwin.EVID_CLSCD_COR_CARD = $c.data.getConstant("EVID_CLSCD_COR_CARD") || "";
    scwin.EVID_CLSCD_PRSN_CARD = $c.data.getConstant("EVID_CLSCD_PRSN_CARD") || "";
    scwin.KOREA_WON = $c.data.getConstant("KOREA_WON") || "KRW";
    scwin.DG_TRUE = 1;

    scwin.f_OnLoad();
};

scwin.onUdcCompleted = function() {
};

scwin.f_OnLoad = async function() {
    $c.gus.cfTurnCreateFlag(true);
    $c.gus.cfDisableKey();

    ds_evidence.removeAll();
    ds_evidence.insertRow(0);

    await $c.sbm.execute(sbm_evidClsCd);
    await $c.sbm.execute(sbm_asetPattern);

    scwin.f_AddAset();
    scwin.f_AddAdjustment();
    scwin.f_Add();

    $c.gus.cfTurnCreateFlag(false);
    lc_evidClsCd.setFocus();
    lc_payCrcCd.setValue(scwin.KOREA_WON);
    $c.gus.cfDisableObjects([ed_payAmtFcrc]);
    lc_acqCls.setSelectedIndex(0);
    ds_evidence.setCellData(0, "evidFileClsCd", "00");
};

scwin.dataSetDebug = function(dataList, isDebug) {
    if (isDebug == true) {
        let str = "[[[[" + dataList.id + "]]]]]\n";
        let colInfos = dataList.getColumnInfo();
        for (let dsRow = 0; dsRow < dataList.getRowCount(); dsRow++) {
            for (let dsCol = 0; dsCol < colInfos.length; dsCol++) {
                let colId = colInfos[dsCol].id;
                str += "[" + colId + "] " + dataList.getCellData(dsRow, colId) + ", ";
            }
            str += "\n\n";
        }
        alert(str);
    }
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.f_Save = async function() {
    scwin.f_SaveProc();
};

scwin.f_SaveProc = async function() {
    let evidFileClsCd = ds_evidence.getCellData(0, "evidFileClsCd");

    if (fileUploadGDS.getRowCount() > 0) {
        if (evidFileClsCd == "" || evidFileClsCd == "00") {
            await $c.win.alert("증빙파일구분을 선택하세요");
            return;
        }
    }

    for (let i = 0; i < ds_adjustment.getRowCount(); i++) {
        if (lc_payCrcCd.getValue() != scwin.KOREA_WON) {
            let changeExchRt = ds_adjustment.getCellData(i, "exchRt");

            dma_exchRtSearch.set("crcCd", ds_adjustment.getCellData(i, "payCrcCd"));
            dma_exchRtSearch.set("stdDt", ed_acqDt.getValue());
            await $c.sbm.execute(sbm_exchRt);

            scwin.checkExchRt = ds_exchRt.getCellData(ds_exchRt.getRowPosition(), "stdExchRt");

            if (changeExchRt < scwin.checkExchRt * 0.9 || changeExchRt > scwin.checkExchRt * 1.1) {
                await $c.win.alert('통화코드 선택시 환율 금액 : ' + scwin.checkExchRt + '원' + '\n' +
                    '환율의 90%  가 되는 금액  : ' + Math.round((scwin.checkExchRt * 0.9) * 100) / 100.00 + '원' + '\n' +
                    '환율의 110% 가 되는 금액  : ' + Math.round((scwin.checkExchRt * 1.1) * 100) / 100.00 + '원' + '\n' + '\n' +
                    (i + 1) + "번째행에 입력된 환율은 기준 환율의 " + '\n' + "90% ~ 110% 사이의 값 이어야 합니다.");
                return;
            }
        }
    }

    if (ds_evidence.isUpdated() == false) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
    } else {
        if (!(await scwin.f_Validation())) {
            return;
        }

        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk) {
            for (let i = 0; i < ds_prov.getRowCount(); i++) {
                for (let j = 0; j < ds_provHeader.getRowCount(); j++) {
                    if (ds_prov.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
                        ds_prov.setCellData(i, "summary", ds_provHeader.getCellData(j, "summary"));
                        ds_prov.setCellData(i, "setlDt", ds_provHeader.getCellData(j, "setlDt"));
                        ds_prov.setCellData(i, "bankbookNo", ds_provHeader.getCellData(j, "bankbookNo"));
                        break;
                    }
                }
            }
            await $c.sbm.execute(sbm_master);
        }
    }
};

scwin.f_Validation = async function() {
    if ((await scwin.f_ValidateEvidence()) == false)
        return false;

    if ((await scwin.f_ValidateAdjustment()) == false)
        return false;

    if ((await scwin.f_ValidateAset()) == false)
        return false;

    if ((await scwin.f_ValidateAreaMgnt()) == false)
        return false;

    let outbrCheck = 0;
    let etcCheck = 0;
    let reqAmt = 0;

    for (let i = 0; i < ds_adjustment.getRowCount(); i++) {
        if (ds_adjustment.getCellData(i, "outbrAcctCd") == "7" || ds_adjustment.getCellData(i, "outbrAcctCd") == "5") {
            outbrCheck = outbrCheck + 1;
        } else {
            reqAmt = reqAmt + Number(ds_adjustment.getCellData(i, "reqAmt"));
            etcCheck = etcCheck + 1;
        }
    }

    let row = 0;

    if (outbrCheck > 0 && etcCheck > 0) {
        if ((Number(ds_evidence.getCellData(row, "spplyAmt")) + Number(ds_evidence.getCellData(row, "vat"))) != reqAmt) {
            await $c.gus.cfAlertMsg("공급가액과 부가세액의 합과 정산금액의 합계가 틀립니다.");
            ed_spplyAmt.setFocus();
            return false;
        }
    } else {
        let adjReqAmtSum = 0;
        for (let k = 0; k < ds_adjustment.getRowCount(); k++) {
            adjReqAmtSum += Number(ds_adjustment.getCellData(k, "reqAmt"));
        }
        if ((Number(ds_evidence.getCellData(row, "spplyAmt")) + Number(ds_evidence.getCellData(row, "vat"))) != adjReqAmtSum) {
            await $c.gus.cfAlertMsg("공급가액과 부가세액의 합과 정산금액의 합계가 틀립니다.");
            ed_spplyAmt.setFocus();
            return false;
        }

        let acqAmtSum = 0;
        for (let k = 0; k < ds_aset.getRowCount(); k++) {
            acqAmtSum += Number(ds_aset.getCellData(k, "acqAmt"));
        }

        if (lc_deductClsCd.getValue() == scwin.NO_DEDUCT_CLS_CD) {
            if ((Number(ds_evidence.getCellData(row, "spplyAmt")) + Number(ds_evidence.getCellData(row, "vat"))) != acqAmtSum) {
                await $c.gus.cfAlertMsg("공급가액과 부가세액의 합과 취득금액의 합계가 틀립니다.");
                ed_spplyAmt.setFocus();
                return false;
            }
        } else {
            if (Number(ed_spplyAmt.getValue()) != acqAmtSum) {
                await $c.gus.cfAlertMsg("공급가액과 취득금액의 합계가 틀립니다.");
                ed_spplyAmt.setFocus();
                return false;
            }
        }
    }

    if (lc_acqCls.getValue() == "20") {
        if (lc_outbrAcctCd.getValue() != "2" && lc_outbrAcctCd.getValue() != "11") {
            if (Number(ed_reqAmt.getValue()) != Number(ed_acqAmt.getValue())) {
                await $c.win.alert("금융리스 자산취득시 장기미지급금-리스부채는 공급가액과 일치해야 하고 미지급금은 부가세액과 일치해야 합니다.");
                return false;
            }
        }

        if (lc_outbrAcctCd.getValue() == "2") {
            if (Number(ed_vat.getValue()) != Number(ed_reqAmt.getValue())) {
                await $c.win.alert("금융리스 자산취득시 장기미지급금-리스부채는 공급가액과 일치해야 하고 미지급금은 부가세액과 일치해야 합니다.");
                return false;
            }
        }
    }

    return true;
};

scwin.f_ValidateEvidence = async function() {
    let chk = await $c.gus.cfValidate([tbl_evidence]);
    if (!chk) {
        return false;
    }

    if (ed_supplierCrn.getValue() != scwin.hid_supplierCrn) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["사업자번호"]);
        ed_supplierCrn.setFocus();
        return false;
    }
    if (ed_vatDeclarAcctDeptCd.getValue() != scwin.hid_vatDeclarAcctDeptCd) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["부가세관리부서"]);
        ed_vatDeclarAcctDeptCd.setFocus();
        return false;
    }

    return true;
};

scwin.f_ValidateAdjustment = async function() {
    if (ds_adjustment.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["정산내역"]);
        return false;
    }

    let chk = await $c.gus.cfValidate([tbl_adjustment]);
    if (!chk) {
        return false;
    }

    if (ed_adjmAcctDeptCd.getValue().trim() != scwin.hid_adjmAcctDeptCd) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["정산귀속부서"]);
        ed_adjmAcctDeptCd.setFocus();
        return false;
    }

    if (ed_clntNo.getValue().trim() != scwin.hid_clntNo) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["정산처"]);
        ed_clntNo.setFocus();
        return false;
    }

    if (lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_NOPAY) {
        if (lc_reqPayMthdCd.getSelectedIndex() < 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["지급수단"]);
            lc_reqPayMthdCd.setFocus();
            return false;
        }
        if (!$c.gus.cfValidateValue(ed_payDt.getValue(), "date=YYYYMMDD")) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["지급예정일"]);
            ed_payDt.setFocus();
            return false;
        }
    }

    let adjmAmt = 0, adjmAmtFcrc = 0, prepaySum = 0, prepaySumFcrc = 0;
    let adjmRow = ds_adjustment.getRowPosition();
    let adjmGubun = ds_adjustment.getCellData(adjmRow, "outbrAcctCd");

    if (adjmGubun == scwin.ADJM_MTHDCD_SUSPAY) {
        adjmAmt = Number(ds_adjustment.getCellData(adjmRow, "reqAmt"));
        adjmAmtFcrc = Number(ds_adjustment.getCellData(adjmRow, "payAmtFcrc"));
        for (let j = 0; j < ds_prov.getRowCount(); j++) {
            if (ds_adjustment.getCellData(adjmRow, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
                prepaySum = prepaySum + Number(ds_prov.getCellData(j, "setlIntendAmt"));
                prepaySumFcrc = prepaySumFcrc + Number(ds_prov.getCellData(j, "setlIntendAmtFcrc"));
            }
        }

        if (prepaySum == 0 && lc_payCrcCd.getValue() == scwin.KOREA_WON) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["정리금액"]);
            return false;
        }

        if (adjmAmt != prepaySum && lc_payCrcCd.getValue() == scwin.KOREA_WON) {
            let alertMsg = ((adjmGubun == scwin.ADJM_MTHDCD_PREPAY) ? "선급금" : "가지급금")
                + " 정산금액과 정리 금액의 합계가 다릅니다.";
            await $c.gus.cfAlertMsg(alertMsg);
            ed_reqAmt.setFocus();
            return false;
        }

        if (prepaySumFcrc == 0 && lc_payCrcCd.getValue() != scwin.KOREA_WON) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["정리외화금액"]);
            return false;
        }

        if (adjmAmtFcrc != prepaySumFcrc && lc_payCrcCd.getValue() != scwin.KOREA_WON) {
            let alertMsg = ((adjmGubun == scwin.ADJM_MTHDCD_PREPAY) ? "선급금" : "가지급금")
                + " 정산외화금액과 정리외화 금액의 합계가 다릅니다.";
            await $c.gus.cfAlertMsg(alertMsg);
            ed_reqAmt.setFocus();
            return false;
        }
    }

    return true;
};

scwin.f_ValidateAset = async function() {
    if (ds_aset.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["취득자산"]);
        return false;
    }

    let chk = await $c.gus.cfValidate([tbl_aset]);
    if (!chk) {
        return false;
    }
    if (scwin.hid_asetKndNm == "" || txt_asetKndNm.getValue() != scwin.hid_asetKndNm) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["자산종류"]);
        txt_asetKndNm.setFocus();
        return false;
    }
    if (ed_acqAcctDeptCd.getValue() != scwin.hid_acqAcctDeptCd) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["귀속부서"]);
        ed_acqAcctDeptCd.setFocus();
        return false;
    }

    if ((await scwin.f_ValidateAcqCls()) == false) return false;

    return true;
};

scwin.f_ValidateAcqCls = async function() {
    let tempAcqCls = "";
    let cntAcctCd = 0;

    for (let i = 0; i < ds_adjustment.getRowCount(); i++) {
        if (ds_adjustment.getCellData(i, "outbrAcctCd") == "11")
            cntAcctCd = cntAcctCd + 1;
    }

    if (lc_acqCls.getValue() == "20" || lc_acqCls.getValue() == "30") {
        if ($c.gus.cfIsNull(ica_acqClsStdt.getValue()) || $c.gus.cfIsNull(ica_acqClsEnddt.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["리스/할부기간(이)"]);
            return false;
        }
        if ($c.gus.cfIsNull(ed_lsClntNo.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["리스/할부거래처"]);
            return false;
        }
    }

    if (lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_LONG_NOPAY && lc_acqCls.getValue() != "30") {
        await $c.gus.cfAlertMsg("정산방법이 장기미지급금-일반인 경우 취득구분은 할부금융이여야 합니다.");
        lc_acqCls.setFocus();
        return false;
    } else if (lc_outbrAcctCd.getValue() != scwin.ADJM_MTHDCD_LONG_NOPAY && lc_acqCls.getValue() == "30") {
        await $c.gus.cfAlertMsg("취득구분이 할부금융인 경우 정산방법은 장기미지급금-일반이여야 합니다.");
        lc_acqCls.setFocus();
        return false;
    } else if (cntAcctCd < 1 && lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_LONG_NOPAY_LEASE && lc_acqCls.getValue() != "20") {
        await $c.gus.cfAlertMsg("정산방법이 장기미지급금-리스부채인 경우 취득구분은 금융리스이여야 합니다.");
        lc_acqCls.setFocus();
        return false;
    } else if (cntAcctCd < 1 && lc_outbrAcctCd.getValue() != scwin.ADJM_MTHDCD_LONG_NOPAY_LEASE && lc_acqCls.getValue() == "20") {
        await $c.gus.cfAlertMsg("취득구분이 금융리스인 경우 정산방법은 장기미지급금-리스부채이여야 합니다.");
        lc_acqCls.setFocus();
        return false;
    } else if ((lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_LONG_NOPAY_LEASE || lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_LONG_NOPAY) && lc_acqCls.getValue() == "10") {
        await $c.gus.cfAlertMsg("정산방법이 장기미지급금-리스부채나 일반인 경우 취득구분은 현금을 선택 할 수 없습니다.");
        lc_acqCls.setFocus();
        return false;
    }

    for (let i = 0; i < ds_aset.getRowCount(); i++) {
        if (i > 0 && (tempAcqCls != ds_aset.getCellData(i, "acqCls"))) {
            await $c.gus.cfAlertMsg("취득구분은 모두 같아야합니다..");
            lc_acqCls.setFocus();
            return false;
        }
        tempAcqCls = ds_aset.getCellData(i, "acqCls");
    }

    return true;
};

scwin.f_ValidateAreaMgnt = async function() {
    if (chb_areaMgntYn.getValue() != "1" && chb_areaMgntYn.getValue() != "true")
        return true;

    if ($c.gus.cfIsNull(ed_zip.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["우편번호"]);
        ed_zip.setFocus();
        return false;
    }

    if ($c.gus.cfIsNull(txt_siteAddr1.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["주소"]);
        ed_zip.setFocus();
        return false;
    }

    if ($c.gus.cfIsNull(txt_siteAddr2.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["상세주소"]);
        txt_siteAddr2.setFocus();
        return false;
    }

    if ($c.gus.cfIsNull(ed_area.getValue()) || parseInt(ed_area.getValue()) <= 0) {
        await $c.gus.cfAlertMsg("면적은 0보다 큰 값이어야 합니다.");
        ed_area.setFocus();
        return false;
    }

    if ($c.gus.cfIsNull(ed_pyCnt.getValue()) || parseInt(ed_pyCnt.getValue()) <= 0) {
        await $c.gus.cfAlertMsg("평수는 0보다 큰 값이어야 합니다.");
        ed_pyCnt.setFocus();
        return false;
    }

    let chk = await $c.gus.cfValidate([gr_master]);
    if (!chk) return false;

    if (ds_master.getRowCount() < 1) {
        await $c.gus.cfAlertMsg("지번_지목 내역을 한 행이상 입력해야 합니다.");
        return false;
    }

    let lotAreaSum = 0;
    for (let k = 0; k < ds_master.getRowCount(); k++) {
        lotAreaSum += Number(ds_master.getCellData(k, "lotArea"));
    }
    if (lotAreaSum != parseInt(ed_area.getValue())) {
        await $c.gus.cfAlertMsg("면적과 지번면적 합계가 틀립니다.");
        ed_area.setFocus();
        return false;
    }

    let lotAcqAmtSum = 0;
    for (let k = 0; k < ds_master.getRowCount(); k++) {
        lotAcqAmtSum += Number(ds_master.getCellData(k, "lotAcqAmt"));
    }
    if (lotAcqAmtSum != parseInt(ed_acqAmt.getValue())) {
        await $c.gus.cfAlertMsg("취득금액과 지번취득금액 합계가 틀립니다.");
        ed_acqAmt.setFocus();
        return false;
    }

    scwin.f_SaveData();

    return true;
};

scwin.f_CalEndDt = function(mm) {
    if (mm == "" || mm == "0" || ica_acqClsStdt.getValue() == "") {
        ica_acqClsEnddt.setValue("");
        ed_lsTerm.setValue("");
        return;
    }
    let startDtm = ica_acqClsStdt.getValue();
    if (startDtm.length == 8 && parseInt(mm, 10) > 0) {
        let startDate = new Date(parseInt(startDtm.substring(0, 4), 10), parseInt(startDtm.substring(4, 6), 10) - 1, parseInt(startDtm.substring(6, 8), 10));
        startDate.setHours(0);
        startDate.setMinutes(0);
        startDate.setSeconds(0);

        let endDate = startDate;
        let curMonth = endDate.getMonth() + 1;
        let plusMonth = curMonth + parseInt(mm, 10);
        if (plusMonth > 12) {
            let share = Math.floor(plusMonth / 12);
            endDate.setFullYear(endDate.getFullYear() + share);

            let rest = plusMonth % 12;
            if (rest > 0) {
                endDate.setMonth(rest - 1);
            } else {
                endDate.setMonth(0);
            }
        } else {
            endDate.setMonth(plusMonth - 1);
        }
        let yyyy = endDate.getFullYear();
        let mmStr = String(endDate.getMonth() + 1).padStart(2, '0');
        let dd = String(endDate.getDate()).padStart(2, '0');
        ica_acqClsEnddt.setValue(yyyy + mmStr + dd);
    }
};

