scwin.f_CopyRow = async function() {
    if (ds_aset.getRowCount() > 0) {
        let chk = await $c.gus.cfValidate([tbl_aset]);
        if (!chk) return;
    }
    if (ds_aset.getRowCount() > 0 && (await scwin.f_ValidateAreaMgnt()) == false) return;
    if (ds_aset.getRowCount() > 0 && (await scwin.f_ValidateAcqCls()) == false) return;

    let curRow = ds_aset.getRowPosition();
    let newIdx = ds_aset.insertRow(ds_aset.getRowCount());
    let colInfos = ds_aset.getColumnInfo();
    for (let c = 0; c < colInfos.length; c++) {
        let colId = colInfos[c].id;
        ds_aset.setCellData(newIdx, colId, ds_aset.getCellData(curRow, colId));
    }
};

scwin.f_AddAset = async function() {
    if (ds_aset.getRowCount() > 0) {
        let chk = await $c.gus.cfValidate([tbl_aset]);
        if (!chk) return;
    }
    if (ds_aset.getRowCount() > 0 && (await scwin.f_ValidateAreaMgnt()) == false) return;
    if (ds_aset.getRowCount() > 0 && (await scwin.f_ValidateAcqCls()) == false) return;

    ds_aset.insertRow(ds_aset.getRowCount());
    ds_landinfo.insertRow(ds_landinfo.getRowCount());
    ds_asetKnd.removeAll();

    scwin.f_AreaMgntOnOff(false);

    ds_aset.setCellData(ds_aset.getRowPosition(), "acqDt", ed_spplyDt.getValue());

    let tempAsetNo = scwin.f_CreatTempNo();
    ds_aset.setCellData(ds_aset.getRowPosition(), "tempAsetNo", tempAsetNo);
    ds_aset.setCellData(ds_aset.getRowPosition(), "crcCd", scwin.KOREA_WON);
    ds_landinfo.setCellData(ds_landinfo.getRowPosition(), "tempAsetNo", tempAsetNo);

