scwin.f_GetObjValue = function(inObj) {
    if (typeof inObj === "string") return inObj;
    if (inObj && typeof inObj.getValue === "function") return inObj.getValue().trim();
    return "";
};

scwin.f_SetObjValue = function(inObj, val) {
    if (typeof inObj === "string") {
        return;
    }
    if (inObj && typeof inObj.setValue === "function") {
        inObj.setValue(val);
    }
};

scwin.f_PopUp = function(cdObj, nmObj, hidObjName, nextObj, sIsEvent, sQueryID, sWhere, sWidth) {
    let rtnList = null, param1, param2;
    let bReverse = false;

    param1 = scwin.f_GetObjValue(cdObj);
    param2 = "";

    rtnList = $c.gus.cfCommonPopUp(sQueryID, param1, param2,
        sIsEvent, null, null, null, null,
        sWhere, sWidth, null, null, null);

    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            if (cdObj && typeof cdObj.setFocus === "function") cdObj.setFocus();
            return null;
        }

        scwin.f_SetObjValue(cdObj, rtnList[0]);
        scwin[hidObjName] = rtnList[0];
        scwin.f_SetObjValue(nmObj, rtnList[1]);
    } else {
        scwin.f_SetObjValue(cdObj, "");
        scwin[hidObjName] = "";
        scwin.f_SetObjValue(nmObj, "");
        if (cdObj && typeof cdObj.setFocus === "function") cdObj.setFocus();
    }

    return rtnList;
};

scwin.f_IsPopUp = function(inObj, hidValue) {
    let inValue = scwin.f_GetObjValue(inObj);

    if ($c.gus.cfIsNull(inValue)) {
        for (let i = 2; i < arguments.length; i++) {
            scwin.f_SetObjValue(arguments[i], "");
        }
        return false;
    }
    if (inValue == hidValue) return false;

    return true;
};

