    let chk = await $c.gus.cfValidate([ed_spplyDt, ed_vatDeclarAcctDeptCd, ed_reqAmt]);
    if (!chk) return false;

    let sum;
    if (lc_payCrcCd.getValue() == scwin.KOREA_WON)
        sum = Number(ed_reqAmt.getValue().trim());
    else
        sum = Number(ed_payAmtFcrc.getValue().trim());

    ds_adjustment.setCellData(ds_adjustment.getRowPosition(), "rltSeq", String(ds_adjustment.getRowPosition()));

    let valueObject = {};
    valueObject.prov = ds_prov;
    valueObject.provHeader = ds_provHeader;
    valueObject.txtrltSeq = ds_adjustment.getCellData(ds_adjustment.getRowPosition(), "rltSeq");
    valueObject.adjmClsCd = lc_outbrAcctCd.getValue();
    valueObject.compare = "2";
    valueObject.sum = sum;
    valueObject.crcCd = lc_payCrcCd.getValue();
    valueObject.acctDeptCd = ed_adjmAcctDeptCd.getValue();
    valueObject.acctDeptNm = txt_adjmAcctDeptNm.getValue();

    let strPath = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml";
    let returnValue = await $c.win.openPopup(strPath, {
        width: 1000,
        height: 520,
        modal: true,
        data: valueObject
    });

    if (returnValue != null) {
        // TODO: import returnValue.provHeader and returnValue.prov into ds_provHeader and ds_prov

        for (let i = 0; i < ds_prov.getRowCount() - 1; i++) {
            for (let j = i + 1; j < ds_prov.getRowCount(); j++) {
                if (ds_prov.getCellData(i, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
                    if (ds_prov.getCellData(i, "slipNo") == ds_prov.getCellData(j, "slipNo")) {
                        ds_prov.removeRow(i);
                        break;
                    }
                }
            }
        }

        for (let i = 0; i < ds_provHeader.getRowCount() - 1; i++) {
            for (let j = i + 1; j < ds_provHeader.getRowCount(); j++) {
                if (ds_provHeader.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
                    ds_provHeader.removeRow(i);
                    break;
                }
            }
        }
    }
};

