scwin.f_FindLandInfo = function(tempNo) {
    if ($c.gus.cfIsNull(tempNo)) return -1;
    return scwin.f_FindDataRow(ds_landinfo, "tempAsetNo", tempNo);
};

scwin.f_CancelDataRow = function(objDataList, sColumn, tempNo) {
    if ($c.gus.cfIsNull(tempNo)) return;

    for (let i = objDataList.getRowCount() - 1; i >= 0; i--) {
        if (objDataList.getCellData(i, sColumn) == tempNo) {
            objDataList.undoRow(i);
        }
    }
};

scwin.f_CancelLandInfo = function(tempNo) {
    if ($c.gus.cfIsNull(tempNo)) return;
    scwin.f_CancelDataRow(ds_landinfo, "tempAsetNo", tempNo);
};

scwin.f_CancelLandInfo2 = function(tempAsetNo) {
    let rowCnt = 0;

    if (tempAsetNo == "") return;

    for (let i = 0; i < ds_landinfo.getRowCount(); i++) {
        if (ds_landinfo.getCellData(i, "tempAsetNo") == tempAsetNo) {
            rowCnt++;
        }
    }

    for (let i = ds_landinfo.getRowCount() - 1; i >= 0; i--) {
        if (ds_landinfo.getCellData(i, "tempAsetNo") == tempAsetNo) {
            ds_landinfo.removeRow(i);
            rowCnt--;
        }
    }
};

