scwin.f_vatDeclarDeptPopUp = function(sIsEvent) {
    let param = ',,1,' + scwin.vCoCd + "," + scwin.vCoClsCd + "," + (ed_spplyDt.getValue() || "").substring(0, 4);

    let rtnList = $c.gus.cfCommonPopUp("retrieveVatDeclarAcctDeptCd",
        ed_vatDeclarAcctDeptCd.getValue(), "",
        sIsEvent, null, null, null, null,
        param, "410", null, null, null);

    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            ed_vatDeclarAcctDeptCd.setFocus();
            return;
        }
        ed_vatDeclarAcctDeptCd.setValue(rtnList[2]);
        scwin.hid_vatDeclarAcctDeptCd = rtnList[2];
        txt_vatDeclarAcctDeptNm.setValue(rtnList[3]);
        ed_vatSpplierCrn.setValue(rtnList[5]);
    } else {
        ed_vatDeclarAcctDeptCd.setValue("");
        scwin.hid_vatDeclarAcctDeptCd = "";
        txt_vatDeclarAcctDeptNm.setValue("");
        ed_vatSpplierCrn.setValue("");
        ed_vatDeclarAcctDeptCd.setFocus();
    }
};

scwin.f_CheckComboData = async function(objCombo, comboTitle) {
    if (objCombo.getSelectedIndex() == -1 && !$c.gus.cfIsNull(objCombo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, [comboTitle + "코드"]);
        objCombo.setFocus();
    }
};

scwin.f_SetExchRt = async function() {
    let stdDt = ed_acqDt.getValue();
    let crcCd = lc_crcCd.getValue();

    if (crcCd == scwin.KOREA_WON) {
        ed_exchRt.setValue(0);
        ed_acqAmtFcrc.setValue(0);
        $c.gus.cfDisableObjects([ed_exchRt, ed_acqAmtFcrc]);
    } else {
        $c.gus.cfEnableObjects([ed_exchRt, ed_acqAmtFcrc]);

        if ($c.gus.cfIsNull(stdDt))
            return;

        dma_exchRtSearch.set("crcCd", crcCd);
        dma_exchRtSearch.set("stdDt", stdDt);
        await $c.sbm.execute(sbm_exchRt);
    }
};

scwin.f_SetAdjustExchRt = async function() {
    let stdDt = scwin.g_sCurrDate;
    let crcCd = lc_payCrcCd.getValue();

    if (crcCd == scwin.KOREA_WON) {
        ed_adjustExchRt.setValue(0);
        ed_payAmtFcrc.setValue(0);
        $c.gus.cfDisableObjects([ed_adjustExchRt, ed_payAmtFcrc]);
        ed_reqAmt.setValue(0);
    } else {
        $c.gus.cfEnableObjects([ed_adjustExchRt, ed_exchRt, ed_acqAmtFcrc]);

        if ($c.gus.cfIsNull(stdDt)) return;

        dma_exchRtSearch.set("crcCd", crcCd);
        dma_exchRtSearch.set("stdDt", stdDt);
        ed_reqAmt.setValue(0);
        ed_payAmtFcrc.setValue(0);
        await $c.sbm.execute(sbm_exchRt);
        scwin.checkExchRt = ds_exchRt.getCellData(ds_exchRt.getRowPosition(), "stdExchRt");
        ed_adjustExchRt.setValue(ds_exchRt.getCellData(0, "stdExchRt"));
    }
};

scwin.f_SetAcqAmt = function(crcCd) {
    if (crcCd == scwin.KOREA_WON) return;
    ed_acqAmt.setValue(Math.round(Number(ed_exchRt.getValue()) * Number(ed_acqAmtFcrc.getValue())));
};

