scwin.f_Add = function() {
    ds_master.insertRow(ds_master.getRowCount());
    ds_master.setCellData(ds_master.getRowPosition(), "tempAsetNo", ds_aset.getCellData(ds_aset.getRowPosition(), "tempAsetNo"));
    gr_master.setFocusedCell(ds_master.getRowPosition(), "lotNo", true);
};

scwin.f_Delete = async function() {
    let rowCnt = 0;
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getRowStatus(i) == "D")
            rowCnt++;
    }
    if ((ds_master.getRowCount() - rowCnt) == 1) {
        await $c.gus.cfAlertMsg("마지막 행은 삭제할 수 없습니다.");
        return;
    }
    ds_master.removeRow(ds_master.getRowPosition());
};

scwin.f_Cancel = function() {
    ds_master.undoRow(ds_master.getRowPosition());
};

scwin.f_CopyDSetHeader = function(ds_source, ds_target) {
    ds_target.removeAll();
};

scwin.f_RetrieveData = function() {
    scwin.f_CopyDataSet(ds_landinfo, ds_master);
};

scwin.f_CopyDataSet = function(ds_source, ds_target) {
    let currentTempAsetNo = ds_aset.getCellData(ds_aset.getRowPosition(), "tempAsetNo");
    for (let i = 0; i < ds_source.getRowCount(); i++) {
        if (ds_source.getCellData(i, "tempAsetNo") == currentTempAsetNo) {
            let newIdx = ds_target.insertRow(ds_target.getRowCount());
            let colInfos = ds_source.getColumnInfo();
            for (let c = 0; c < colInfos.length; c++) {
                let colId = colInfos[c].id;
                ds_target.setCellData(newIdx, colId, ds_source.getCellData(i, colId));
            }
        }
    }
};

scwin.f_SaveData = function() {
    let changeExchRt = ds_adjustment.getCellData(ds_adjustment.getRowPosition(), "exchRt");

    if (!$c.gus.cfCheckExchRt(scwin.checkExchRt, changeExchRt, scwin.checkMain))
        return;

    let currentTempAsetNo = ds_aset.getCellData(ds_aset.getRowPosition(), "tempAsetNo");
    scwin.f_UndoAllValueRow(ds_landinfo, "tempAsetNo", currentTempAsetNo);
    scwin.f_CopyDataSet(ds_master, ds_landinfo);
};

scwin.f_UndoAllValueRow = function(dataList, sColumn, columnValue) {
    if (dataList == null) return;
    if (sColumn == "") return;
    if (columnValue == "") return;

    let foundRow = scwin.f_FindValueRow(dataList, sColumn, columnValue);
    while (foundRow >= 0) {
        dataList.undoRow(foundRow);
        foundRow = scwin.f_FindValueRow(dataList, sColumn, columnValue);
    }
};

scwin.f_FindValueRow = function(dataList, sColumn, columnValue) {
    if ($c.gus.cfIsNull(columnValue)) return -1;

    for (let i = 0; i < dataList.getRowCount(); i++) {
        if (dataList.getCellData(i, sColumn) == columnValue) {
            return i;
        }
    }
    return -1;
};

