    let areaMgntYn = 0;
    if (patternRow >= 0) {
        areaMgntYn = ds_asetPattern.getCellData(patternRow, "areaMgntYn");
    }
    ds_aset.setCellData(ds_aset.getRowPosition(), "areaMgntYn", areaMgntYn);

    if (areaMgntYn == scwin.DG_TRUE) {
